import sys
from math import isqrt

def main():
    data = sys.stdin.buffer.read().split()
    idx = 0
    n, m = int(data[idx]), int(data[idx+1]); idx += 2

    X = [0] * (n + 1)
    Y = [0] * (n + 1)
    for i in range(1, n + 1):
        X[i], Y[i] = int(data[idx]), int(data[idx+1]); idx += 2

    B = 700  # block size
    # For small period trains: cnt[p][r] = number of active trains with period p, where on day d, (d - t) % p >= x means d % p in maintenance range
    # Use dict of dicts
    small = {}  # small[p][r] = count of trains where "maintenance starts at residue r mod p"

    active = {}  # train_id -> (t, x, y)
    large_trains = {}  # train_id -> (t, x, y) for large period trains

    out = []

    for day in range(1, m + 1):
        op, k = int(data[idx]), int(data[idx+1]); idx += 2

        x, y = X[k], Y[k]
        p = x + y

        if op == 1:
            active[k] = (day, x, y)
            if p <= B:
                if p not in small:
                    small[p] = [0] * p
                # maintenance days: residues (day + x) % p ... (day + x + y - 1) % p
                start = (day + x) % p
                for i in range(y):
                    small[p][(start + i) % p] += 1
            else:
                large_trains[k] = (day, x, y)
        else:
            t, x, y = active.pop(k)
            p = x + y
            if p <= B:
                start = (t + x) % p
                for i in range(y):
                    small[p][(start + i) % p] -= 1
            else:
                large_trains.pop(k)

        count = 0
        for p, arr in small.items():
            count += arr[day % p]
        for kid, (t, x, y) in large_trains.items():
            if (day - t) % (x + y) >= x:
                count += 1

        out.append(count)

    print('\n'.join(map(str, out)))

main()

